const body = $input.item.json.body || $input.item.json;
let sender = '';
let message = '';

if (body.whatsappInboundMessage) {
  sender = body.whatsappInboundMessage.from || '';
  message = body.whatsappInboundMessage.text?.body || '';
} else if (body.from && body.text) {
  sender = body.from;
  message = body.text.body || body.text;
} else {
  sender = body.from || body.sender || '';
  message = body.message || body.text || 'Hola';
}

return {
  sender: sender,
  message: message
};

