// Parse Gemini response
const response = $input.item.json;
let aiText = 'Lo siento, hubo un problema. ¿Podés repetir?';

try {
  if (response.candidates && response.candidates[0]) {
    aiText = response.candidates[0].content.parts[0].text;
  }
} catch (e) {
  console.log('Error parsing Gemini response:', e);
}

// Get sender from previous node
const sender = $('Extract Message').item.json.sender;

return {
  aiText: aiText,
  sender: sender
};
